<?php use function App\Core\{e,url,csrf_field}; ?><section class="card"><h2>テンプレート追加</h2><p>利用可能タグ: {title} {article_url} {affiliate_url} {sample_movie_url} {image_url} {hashtags} {service} {actress} {genre}</p><form method="post" action="<?= e(url('/templates')) ?>"><?= csrf_field() ?><label>名前<input name="name" required></label><label>本文<textarea name="body" required rows="8"></textarea></label><button class="primary">保存</button></form></section><section class="card"><h2>テンプレート一覧</h2><?php foreach($templates as $t): ?><article class="template"><h3><?= e($t['name']) ?></h3><pre><?= e($t['body']) ?></pre><?php if(!$t['is_default']): ?><form method="post" action="<?= e(url('/templates/delete')) ?>"><?= csrf_field() ?><input type="hidden" name="id" value="<?= $t['id'] ?>"><button>削除</button></form><?php endif; ?></article><?php endforeach; ?></section>
